namespace sv_fc0329bd7f72421c81caede6a0f81edc;

public enum ThemeMode
{
    Light,
    Dark,
    System
}

public record ThemeInfo(ThemeMode Mode = ThemeMode.Light, string AccentColor = "#0d6efd");

@rendermode InteractiveServer

<span class="theme-indicator" title="Current theme">
    @ThemeIcon @Theme.Mode
    <span class="accent-dot" style="background-color: @Theme.AccentColor;"></span>
</span>

@code {
    [CascadingParameter]
    private ThemeInfo Theme { get; set; } = new();

    private string ThemeIcon => Theme.Mode switch
    {
        ThemeMode.Dark => "🌙",
        ThemeMode.System => "💻",
        _ => "☀️"
    };
}

.theme-indicator {
    display: inline-flex;
    align-items: center;
    gap: 0.4rem;
    font-size: 0.9rem;
}

.accent-dot {
    display: inline-block;
    width: 12px;
    height: 12px;
    border-radius: 50%;
    border: 1px solid rgba(0, 0, 0, 0.2);
}

@page "/settings"
@rendermode InteractiveServer
@inject CascadingValueSource<ThemeInfo> ThemeSource

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="card mt-4" style="max-width: 500px;">
    <div class="card-body">
        <h5 class="card-title">Theme</h5>

        <div class="mb-3">
            <label class="form-label">Mode</label>
            <select class="form-select" value="@Theme.Mode" @onchange="OnModeChanged">
                @foreach (var mode in Enum.GetValues<ThemeMode>())
                {
                    <option value="@mode">@mode</option>
                }
            </select>
        </div>

        <div class="mb-3">
            <label class="form-label">Accent Color</label>
            <div class="d-flex align-items-center gap-2">
                <input type="color" class="form-control form-control-color"
                       value="@Theme.AccentColor" @onchange="OnAccentChanged" />
                <span class="text-muted">@Theme.AccentColor</span>
            </div>
        </div>

        <div class="alert alert-info mt-3 mb-0">
            Current: <strong>@Theme.Mode</strong> mode with accent
            <span style="color: @Theme.AccentColor; font-weight: bold;">@Theme.AccentColor</span>.
            Changes apply immediately across all components.
        </div>
    </div>
</div>

@code {
    [CascadingParameter]
    private ThemeInfo Theme { get; set; } = new();

    private async Task OnModeChanged(ChangeEventArgs e)
    {
        var newMode = Enum.Parse<ThemeMode>(e.Value!.ToString()!);
        await ThemeSource.NotifyChangedAsync(Theme with { Mode = newMode });
    }

    private async Task OnAccentChanged(ChangeEventArgs e)
    {
        await ThemeSource.NotifyChangedAsync(Theme with { AccentColor = e.Value!.ToString()! });
    }
}

